-- Remove points_awarded values that were written by insertDefaultPredictions
-- for matches that were never actually finished (e.g. test scores set and reverted).
-- Predictions tied to genuinely finished matches are left untouched.
update public.predictions
set points_awarded = null
where match_id in (
  select id from public.matches where status != 'finished'
);

-- Delete prediction rows that were auto-generated by insertDefaultPredictions:
-- those with both predicted scores = 0, points_awarded already set, and
-- the match is still not finished.  Real 0-0 predictions on unfinished matches
-- are also reset above, but we keep the rows so users can still update them.
